values.value:
[
  {
    "name": "from_record",
    "label": "From Record",
    "description": "Read a file attached to the current record. Automatically reads the only file if one is attached, or returns a list for the LLM to choose from when multiple files exist.",
    "configFields": [
      {
        "name": "maxFileSizeKb",
        "type": "integer",
        "required": false,
        "label": "Max File Size (KB)",
        "placeholder": "50",
        "help": "Maximum file size in kilobytes that this tool will attempt to decode. Default: 50 KB."
      },
      {
        "name": "allowedFileExtensions",
        "type": "array",
        "required": false,
        "label": "Allowed File Extensions",
        "placeholder": "[\"csv\",\"txt\",\"json\"]",
        "help": "Optional allowlist of file extensions (lowercase, without the dot). If omitted, all extensions are attempted. If set, only matching extensions are processed."
      }
    ],
    "parameterFields": [
      {
        "name": "linkedEntityId",
        "type": "salesforce-id",
        "required": false,
        "label": "Linked Entity ID",
        "placeholder": "001000000000000AAA",
        "help": "Salesforce ID of the record the file is attached to. Omit to use the record that triggered this agent."
      },
      {
        "name": "contentDocumentId",
        "type": "salesforce-id",
        "required": false,
        "label": "Content Document ID",
        "placeholder": "069000000000000AAA",
        "help": "Salesforce ContentDocument ID. Provide this directly to skip the file discovery step when you already know which file to read."
      }
    ],
    "configJsonSchema": {
      "$schema": "http://json-schema.org/draft-07/schema#",
      "type": "object",
      "properties": {
        "variant": { "type": "string", "enum": ["from_record"] },
        "maxFileSizeKb": { "type": "integer", "description": "Maximum file size in kilobytes. Default: 50." },
        "allowedFileExtensions": {
          "type": "array",
          "items": { "type": "string" },
          "description": "Optional allowlist of file extensions (lowercase, without the dot)."
        }
      }
    },
    "parametersJsonSchema": {
      "$schema": "http://json-schema.org/draft-07/schema#",
      "type": "object",
      "properties": {
        "linkedEntityId": {
          "type": "string",
          "description": "Salesforce ID of the record the file is attached to. Omit to use the record that triggered this agent.",
          "format": "salesforce-id"
        },
        "contentDocumentId": {
          "type": "string",
          "description": "Salesforce ContentDocument ID of the file to read. Provide this directly when you already know which file to read.",
          "format": "salesforce-id"
        }
      },
      "required": []
    }
  },
  {
    "name": "by_file_id",
    "label": "By File ID",
    "description": "Read a specific file using its Salesforce ContentDocument ID. Best for email agents where file IDs are surfaced in the email context block.",
    "configFields": [
      {
        "name": "maxFileSizeKb",
        "type": "integer",
        "required": false,
        "label": "Max File Size (KB)",
        "placeholder": "50",
        "help": "Maximum file size in kilobytes that this tool will attempt to decode. Default: 50 KB."
      },
      {
        "name": "allowedFileExtensions",
        "type": "array",
        "required": false,
        "label": "Allowed File Extensions",
        "placeholder": "[\"csv\",\"txt\",\"json\"]",
        "help": "Optional allowlist of file extensions (lowercase, without the dot). If omitted, all extensions are attempted. If set, only matching extensions are processed."
      }
    ],
    "parameterFields": [
      {
        "name": "contentDocumentId",
        "type": "salesforce-id",
        "required": true,
        "label": "Content Document ID",
        "placeholder": "069000000000000AAA",
        "help": "Salesforce ContentDocument ID of the file to read. File IDs are shown in the email attachment list."
      }
    ],
    "configJsonSchema": {
      "$schema": "http://json-schema.org/draft-07/schema#",
      "type": "object",
      "properties": {
        "variant": { "type": "string", "enum": ["by_file_id"] },
        "maxFileSizeKb": { "type": "integer", "description": "Maximum file size in kilobytes. Default: 50." },
        "allowedFileExtensions": {
          "type": "array",
          "items": { "type": "string" },
          "description": "Optional allowlist of file extensions (lowercase, without the dot)."
        }
      }
    },
    "parametersJsonSchema": {
      "$schema": "http://json-schema.org/draft-07/schema#",
      "type": "object",
      "properties": {
        "contentDocumentId": {
          "type": "string",
          "description": "Salesforce ContentDocument ID of the file to read. Use the file ID shown in the email attachment list.",
          "format": "salesforce-id"
        }
      },
      "required": ["contentDocumentId"]
    }
  }
]
